#include <bits/stdc++.h>
using namespace std;
#define ll long long
const int N=1000005;
int n,nxt[N];
string s;
ll ans;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>s;
	s=" "+s;
	for(int i=2,j=0;i<=n;i++)
	{
		while(j&&(s[i]!=s[j+1])) j=nxt[j];
		if(s[i]==s[j+1]) j++;
		nxt[i]=j;
	}
	for(int i=2,j=2;i<=n;i++,j=i)
	{
		while(nxt[j]) j=nxt[j];
		if(nxt[i]) nxt[i]=j;
		ans+=(i-j);
	}
	cout<<ans;
	return 0;
}
